17	const withFirstInsurance = (base: number): number =>
18	  base + base * FIRST_INSURANCE_SURCHARGE_RATE;
19	
20	const groupBase = (type: string, count: number): number => {
21	  if (COMPONENT_TYPES.has(type) && count === BLOCK_SIZE) {
22	    return withFirstInsurance(BLOCK_BASE_PREMIUM);
23	  }
24	  return count * withFirstInsurance(BASE_PREMIUM[type]);
25	};
